const styles = `
  @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,500;0,600;1,300;1,400&family=Outfit:wght@300;400;500;600&family=JetBrains+Mono:wght@400;500&display=swap');
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  html { scroll-behavior: smooth; }
  body { background: #0a0a0a; color: #F5F5F0; font-family: 'Outfit', sans-serif; font-weight: 300; line-height: 1.6; overflow-x: hidden; }
  ::selection { background: #C9A84C; color: #000; }

  /* NAV */
  nav {
    position: fixed; top: 0; left: 0; right: 0; z-index: 100;
    display: flex; align-items: center; justify-content: space-between;
    padding: 1.1rem 3rem;
    background: rgba(10,10,10,0.92);
    backdrop-filter: blur(24px);
    border-bottom: 1px solid #1a1a1a;
  }
  .nav-logo { font-family: 'Cormorant Garamond', serif; font-size: 1.1rem; font-weight: 500; letter-spacing: 0.15em; color: #C9A84C; text-decoration: none; }
  .nav-links { display: flex; gap: 2.5rem; list-style: none; }
  .nav-links a { font-size: 0.72rem; letter-spacing: 0.12em; text-transform: uppercase; color: #777770; text-decoration: none; transition: color 0.3s; }
  .nav-links a:hover { color: #C9A84C; }
  .nav-right { display: flex; align-items: center; gap: 1.5rem; }

  /* LANGUAGE SWITCHER — Google style */
  .lang-switcher {
    position: relative;
    display: inline-block;
  }
  .lang-btn {
    display: flex; align-items: center; gap: 0.45rem;
    padding: 0.4rem 0.85rem;
    background: transparent;
    border: 1px solid rgba(201,168,76,0.3);
    border-radius: 4px;
    color: #C9A84C;
    font-family: 'Outfit', sans-serif;
    font-size: 0.72rem;
    letter-spacing: 0.1em;
    text-transform: uppercase;
    cursor: pointer;
    transition: all 0.2s;
    white-space: nowrap;
  }
  .lang-btn:hover { border-color: #C9A84C; background: rgba(201,168,76,0.06); }
  .lang-btn svg { width: 14px; height: 14px; flex-shrink: 0; }
  .lang-btn .chevron { width: 10px; height: 10px; transition: transform 0.2s; }
  .lang-btn.open .chevron { transform: rotate(180deg); }

  .lang-dropdown {
    position: absolute; top: calc(100% + 6px); right: 0;
    background: #111;
    border: 1px solid #2a2a2a;
    border-radius: 6px;
    overflow: hidden;
    min-width: 140px;
    box-shadow: 0 8px 32px rgba(0,0,0,0.6);
    z-index: 200;
    animation: fadeIn 0.15s ease;
  }
  @keyframes fadeIn { from { opacity:0; transform:translateY(-6px); } to { opacity:1; transform:translateY(0); } }
  .lang-option {
    display: flex; align-items: center; gap: 0.75rem;
    padding: 0.75rem 1rem;
    cursor: pointer;
    font-size: 0.78rem;
    color: #aaa;
    transition: background 0.15s, color 0.15s;
    letter-spacing: 0.04em;
  }
  .lang-option:hover { background: rgba(201,168,76,0.08); color: #F5F5F0; }
  .lang-option.active { color: #C9A84C; }
  .lang-option .flag { font-size: 1rem; }
  .lang-option .check { margin-left: auto; color: #C9A84C; font-size: 0.7rem; }

  /* HERO */
  .hero { min-height: 100vh; display: flex; flex-direction: column; justify-content: center; padding: 8rem 3rem 4rem; max-width: 900px; margin: 0 auto; }
  .hero-eyebrow { font-size: 0.7rem; letter-spacing: 0.25em; text-transform: uppercase; color: #C9A84C; margin-bottom: 1.5rem; display: flex; align-items: center; gap: 1rem; }
  .hero-eyebrow::before { content: ''; display: block; width: 40px; height: 1px; background: #C9A84C; }
  .hero-content { display: grid; grid-template-columns: 1fr auto; gap: 4rem; align-items: center; }
  .hero-name { font-family: 'Cormorant Garamond', serif; font-size: clamp(2.6rem, 6vw, 5rem); font-weight: 300; line-height: 1.05; color: #F5F5F0; margin-bottom: 0.75rem; }
  .hero-name span { color: #C9A84C; font-style: italic; }
  .hero-title { font-size: 0.78rem; letter-spacing: 0.1em; text-transform: uppercase; color: #777770; margin-bottom: 1.5rem; }
  .hero-bio { font-size: 0.95rem; color: #777770; max-width: 500px; line-height: 1.8; margin-bottom: 2.5rem; }
  .hero-ctas { display: flex; gap: 1rem; flex-wrap: wrap; }
  .btn-primary { padding: 0.85rem 2rem; background: #C9A84C; color: #000; font-family: 'Outfit', sans-serif; font-size: 0.75rem; font-weight: 500; letter-spacing: 0.12em; text-transform: uppercase; border: none; cursor: pointer; text-decoration: none; transition: all 0.3s; display: inline-block; }
  .btn-primary:hover { background: #E2C070; }
  .btn-outline { padding: 0.85rem 2rem; background: transparent; color: #C9A84C; font-family: 'Outfit', sans-serif; font-size: 0.75rem; font-weight: 500; letter-spacing: 0.12em; text-transform: uppercase; border: 1px solid rgba(201,168,76,0.4); cursor: pointer; text-decoration: none; transition: all 0.3s; display: inline-block; }
  .btn-outline:hover { border-color: #C9A84C; }

  .hero-photo-wrap { position: relative; flex-shrink: 0; }
  .hero-photo { width: 260px; height: 340px; object-fit: cover; object-position: top center; display: block; border: 1px solid #1a1a1a; }
  .hero-photo-accent { position: absolute; top: -10px; right: -10px; width: 100%; height: 100%; border: 1px solid rgba(201,168,76,0.25); pointer-events: none; }

  /* STATS */
  .stats-bar { display: grid; grid-template-columns: repeat(4, 1fr); border-top: 1px solid #1a1a1a; border-bottom: 1px solid #1a1a1a; }
  .stat-item { padding: 2rem 3rem; border-right: 1px solid #1a1a1a; }
  .stat-item:last-child { border-right: none; }
  .stat-num { font-family: 'Cormorant Garamond', serif; font-size: 2.5rem; font-weight: 300; color: #C9A84C; display: block; }
  .stat-label { font-size: 0.7rem; letter-spacing: 0.1em; text-transform: uppercase; color: #777770; }

  /* SECTIONS */
  section { padding: 5rem 3rem; max-width: 900px; margin: 0 auto; }
  .section-eyebrow { font-size: 0.65rem; letter-spacing: 0.2em; text-transform: uppercase; color: #8B6914; margin-bottom: 0.75rem; display: flex; align-items: center; gap: 0.75rem; }
  .section-eyebrow::after { content: ''; flex: 1; max-width: 50px; height: 1px; background: #8B6914; }
  .section-title { font-family: 'Cormorant Garamond', serif; font-size: clamp(1.8rem, 3.5vw, 2.8rem); font-weight: 300; color: #F5F5F0; margin-bottom: 3rem; line-height: 1.1; }
  .section-title em { color: #C9A84C; font-style: italic; }

  /* STACK */
  .stack-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(180px, 1fr)); gap: 1px; background: #1a1a1a; border: 1px solid #1a1a1a; }
  .stack-category { background: #111; padding: 1.75rem; }
  .stack-cat-title { font-size: 0.65rem; letter-spacing: 0.15em; text-transform: uppercase; color: #C9A84C; margin-bottom: 1rem; padding-bottom: 0.75rem; border-bottom: 1px solid #1a1a1a; }
  .stack-tags { display: flex; flex-wrap: wrap; gap: 0.4rem; }
  .stack-tag { font-family: 'JetBrains Mono', monospace; font-size: 0.7rem; padding: 0.25rem 0.6rem; background: #0a0a0a; border: 1px solid #222; color: #777770; }

  /* PROJECTS */
  .projects-list { display: flex; flex-direction: column; gap: 1px; background: #1a1a1a; border: 1px solid #1a1a1a; }
  .project-card { background: #111; padding: 2.5rem; display: grid; grid-template-columns: 80px 1fr; gap: 2rem; align-items: start; transition: background 0.2s; }
  .project-card:hover { background: #161616; }
  .project-num { font-family: 'Cormorant Garamond', serif; font-size: 2.5rem; font-weight: 300; color: #222; line-height: 1; padding-top: 0.25rem; }
  .project-top { display: flex; align-items: center; gap: 1rem; margin-bottom: 0.75rem; flex-wrap: wrap; }
  .project-name { font-family: 'Cormorant Garamond', serif; font-size: 1.4rem; font-weight: 400; color: #F5F5F0; }
  .project-client { font-size: 0.62rem; letter-spacing: 0.15em; text-transform: uppercase; color: #C9A84C; padding: 0.15rem 0.5rem; border: 1px solid rgba(201,168,76,0.25); }
  .project-desc { font-size: 0.88rem; color: #777770; line-height: 1.7; margin-bottom: 1.25rem; }
  .project-tags { display: flex; flex-wrap: wrap; gap: 0.35rem; }
  .project-tag { font-family: 'JetBrains Mono', monospace; font-size: 0.62rem; padding: 0.2rem 0.5rem; background: rgba(201,168,76,0.04); border: 1px solid rgba(201,168,76,0.12); color: #8B6914; }
  .project-img { width: 100%; margin-top: 1.5rem; max-width: 220px; border: 1px solid #1a1a1a; display: block; }

  /* TIMELINE */
  .timeline { border-left: 1px solid #1a1a1a; padding-left: 2.5rem; }
  .timeline-item { position: relative; padding-bottom: 3rem; }
  .timeline-item::before { content: ''; position: absolute; left: -2.6rem; top: 5px; width: 10px; height: 10px; border-radius: 50%; background: #0a0a0a; border: 1px solid #C9A84C; }
  .timeline-year { font-family: 'JetBrains Mono', monospace; font-size: 0.68rem; color: #C9A84C; margin-bottom: 0.4rem; }
  .timeline-role { font-family: 'Cormorant Garamond', serif; font-size: 1.25rem; color: #F5F5F0; margin-bottom: 0.2rem; }
  .timeline-company { font-size: 0.72rem; letter-spacing: 0.08em; text-transform: uppercase; color: #8B6914; margin-bottom: 0.75rem; }
  .timeline-desc { font-size: 0.87rem; color: #777770; line-height: 1.7; max-width: 560px; }

  /* CONTACT */
  .contact-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 4rem; padding: 5rem 3rem; max-width: 900px; margin: 0 auto; border-top: 1px solid #1a1a1a; }
  .contact-intro { font-size: 0.92rem; color: #777770; line-height: 1.8; margin-top: 1.5rem; }
  .contact-links { display: flex; flex-direction: column; justify-content: center; }
  .contact-link { display: flex; gap: 1.5rem; align-items: center; padding: 1.25rem 0; border-bottom: 1px solid #1a1a1a; text-decoration: none; color: #F5F5F0; transition: color 0.2s; }
  .contact-link:hover { color: #C9A84C; }
  .contact-link-label { font-size: 0.62rem; letter-spacing: 0.15em; text-transform: uppercase; color: #777770; min-width: 70px; }
  .contact-link-value { font-size: 0.88rem; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }

  /* FOOTER */
  footer { padding: 1.75rem 3rem; display: flex; justify-content: space-between; align-items: center; border-top: 1px solid #1a1a1a; }
  .footer-name { font-family: 'Cormorant Garamond', serif; font-size: 0.95rem; color: #8B6914; letter-spacing: 0.1em; }
  .footer-copy { font-size: 0.65rem; color: #333; letter-spacing: 0.1em; }

  /* REVEAL */
  .reveal { opacity: 0; transform: translateY(24px); transition: opacity 0.6s, transform 0.6s; }
  .reveal.visible { opacity: 1; transform: none; }

  /* MOBILE */
  @media (max-width: 768px) {
    nav { padding: 1rem 1.5rem; }
    .nav-links { display: none; }
    .hero { padding: 7rem 1.5rem 3rem; }
    .hero-content { grid-template-columns: 1fr; gap: 2.5rem; }
    .hero-photo { width: 200px; height: 260px; }
    .stats-bar { grid-template-columns: repeat(2,1fr); }
    .stat-item { padding: 1.5rem; }
    section { padding: 3.5rem 1.5rem; }
    .project-card { grid-template-columns: 1fr; gap: 0; }
    .project-num { display: none; }
    .contact-grid { grid-template-columns: 1fr; gap: 2.5rem; padding: 3rem 1.5rem; }
    footer { padding: 1.5rem; flex-direction: column; gap: 0.5rem; text-align: center; }
  }
`;

// ─── COMPONENT ──────────────────────────────────────────────────────────────
export default function Portfolio() {
  const [lang, setLang] = useState("es");
  const [open, setOpen] = useState(false);
  const dropRef = useRef(null);
  const t = T[lang];

  // Close dropdown on outside click
  useEffect(() => {
    const handler = (e) => { if (dropRef.current && !dropRef.current.contains(e.target)) setOpen(false); };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  // Scroll reveal
  useEffect(() => {
    const els = document.querySelectorAll(".reveal");
    const obs = new IntersectionObserver(entries => {
      entries.forEach(e => { if (e.isIntersecting) e.target.classList.add("visible"); });
    }, { threshold: 0.08 });
    els.forEach(el => obs.observe(el));
    return () => obs.disconnect();
  }, [lang]);

  const langs = [
    { code:"es", label:"Español", flag:"🇲🇽" },
    { code:"en", label:"English", flag:"🇺🇸" },
  ];

  const current = langs.find(l => l.code === lang);
  const navIds = ["proyectos","stack","trayectoria","contacto"];

  return (
    <>
      <style>{styles}</style>

      {/* NAV */}
      <nav>
        <a href="#inicio" className="nav-logo">M · CERVANTES</a>
        <ul className="nav-links">
          {t.nav.map((item, i) => (
            <li key={item}><a href={`#${navIds[i]}`}>{item}</a></li>
          ))}
        </ul>
        <div className="nav-right">
          {/* Language switcher */}
          <div className="lang-switcher" ref={dropRef}>
            <button className={`lang-btn ${open ? "open" : ""}`} onClick={() => setOpen(!open)}>
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
                <circle cx="12" cy="12" r="10"/><path d="M2 12h20M12 2a15.3 15.3 0 0 1 4 10 15.3 15.3 0 0 1-4 10 15.3 15.3 0 0 1-4-10 15.3 15.3 0 0 1 4-10z"/>
              </svg>
              {current.flag} {current.label}
              <svg className="chevron" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                <path d="M6 9l6 6 6-6"/>
              </svg>
            </button>
            {open && (
              <div className="lang-dropdown">
                {langs.map(l => (
                  <div key={l.code} className={`lang-option ${l.code === lang ? "active" : ""}`}
                    onClick={() => { setLang(l.code); setOpen(false); }}>
                    <span className="flag">{l.flag}</span>
                    {l.label}
                    {l.code === lang && <span className="check">✓</span>}
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </nav>

      {/* HERO */}
      <div id="inicio" className="hero">
        <div className="hero-eyebrow">{t.location}</div>
        <div className="hero-content">
          <div>
            <h1 className="hero-name">Marcos Esteban<br /><span>Cervantes Armada</span></h1>
            <p className="hero-title">{t.title}</p>
            <p className="hero-bio">{t.bio}</p>
            <div className="hero-ctas">
              <a href="#proyectos" className="btn-primary">{t.cta1}</a>
              <a href="#contacto" className="btn-outline">{t.cta2}</a>
            </div>
          </div>
          <div className="hero-photo-wrap">
            <img src={PHOTO} alt="Marcos Esteban Cervantes Armada" className="hero-photo" />
            <div className="hero-photo-accent" />
          </div>
        </div>
      </div>

      {/* STATS */}
      <div className="stats-bar reveal">
        {t.stats.map(s => (
          <div key={s.label} className="stat-item">
            <span className="stat-num">{s.num}</span>
            <span className="stat-label">{s.label}</span>
          </div>
        ))}
      </div>

      {/* PROJECTS */}
      <section id="proyectos">
        <div className="reveal">
          <div className="section-eyebrow">{t.s1}</div>
          <h2 className="section-title">{t.s1t} <em>{t.s1em}</em></h2>
        </div>
        <div className="projects-list">
          {t.projects.map((p, i) => (
            <div key={p.num} className="project-card reveal" style={{ transitionDelay:`${i*0.04}s` }}>
              <div className="project-num">{p.num}</div>
              <div>
                <div className="project-top">
                  <span className="project-name">{p.name}</span>
                  <span className="project-client">{p.client}</span>
                </div>
                <p className="project-desc">{p.desc}</p>
                <div className="project-tags">
                  {p.tags.map(tag => <span key={tag} className="project-tag">{tag}</span>)}
                </div>
                {p.img && <img src={AUREXA_IMG} alt="Aurexa App" className="project-img" />}
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* STACK */}
      <section id="stack">
        <div className="reveal">
          <div className="section-eyebrow">{t.s2}</div>
          <h2 className="section-title">{t.s2t} <em>{t.s2em}</em></h2>
        </div>
        <div className="stack-grid reveal">
          {t.techStack.map(cat => (
            <div key={cat.category} className="stack-category">
              <div className="stack-cat-title">{cat.category}</div>
              <div className="stack-tags">
                {cat.tags.map(tag => <span key={tag} className="stack-tag">{tag}</span>)}
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* TIMELINE */}
      <section id="trayectoria">
        <div className="reveal">
          <div className="section-eyebrow">{t.s3}</div>
          <h2 className="section-title">{t.s3t} <em>{t.s3em}</em></h2>
        </div>
        <div className="timeline">
          {t.timeline.map((item, i) => (
            <div key={i} className="timeline-item reveal" style={{ transitionDelay:`${i*0.07}s` }}>
              <div className="timeline-year">{item.year}</div>
              <div className="timeline-role">{item.role}</div>
              <div className="timeline-company">{item.company}</div>
              <div className="timeline-desc">{item.desc}</div>
            </div>
          ))}
        </div>
      </section>

      {/* CONTACT */}
      <div id="contacto" className="contact-grid reveal">
        <div>
          <div className="section-eyebrow">{t.s4}</div>
          <h2 className="section-title" style={{ marginBottom:"1rem" }}>{t.s4t} <em>{t.s4em}</em></h2>
          <p className="contact-intro">{t.contactIntro}</p>
        </div>
        <div className="contact-links">
          {t.contactLinks.map(l => (
            <a key={l.label} href={l.href} className="contact-link" target="_blank" rel="noopener noreferrer">
              <span className="contact-link-label">{l.label}</span>
              <span className="contact-link-value">{l.value}</span>
            </a>
          ))}
        </div>
      </div>

      {/* FOOTER */}
      <footer>
        <span className="footer-name">MARCOS ESTEBAN CERVANTES ARMADA</span>
        <span className="footer-copy">© 2026 · Aguascalientes, México</span>
      </footer>
    </>
  );
}